SELECT 
FROM vso_order t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.order_id = #{orderId}


    AND t.order_no = #{orderNo}


    AND t.order_type = #{orderType}


    AND t.order_source = #{orderSource}


    AND t.customer_type = #{customerType}


    AND t.order_state = #{orderState}


    AND t.brand_code = #{brandCode}


    AND t.region_code = #{regionCode}


    AND t.store_code = #{storeCode}


    AND t.sales_code = #{salesCode}


    AND t.vehicle_vin = #{vehicleVin}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC

SELECT 
FROM vso_order t
WHERE t.row_valid = 1

    AND t.order_state = #{orderState}


    AND t.order_state IN

        #{status}



    AND t.order_no = #{orderNo}


    AND t.store_code = #{storeCode}


    AND t.sales_code = #{salesCode}


    AND t.created_at_business >= #{beginTime}


    AND t.created_at_business <= #{endTime}

ORDER BY t.id DESC

